+            assert_array_matches_numpy(&cast_actual, &cast_expected)?;
+            assert_eq!(
+                cast_actual.getattr("dtype")?.str()?.extract::<String>()?,
+                cast_expected.getattr("dtype")?.str()?.extract::<String>()?
+            );
+
+            // Mismatched-shape error parity.
